from typing import Dict, Any
import yaml

def generate_docker_compose(
    app_name: str,
    enable_jupyter: bool = True,
    enable_cache: bool = True,
    app_port: int = 8000,
    jupyter_port: int = 8888
) -> str:
    """
    Generate docker-compose.yml content for quantum development.
    """
    compose = {
        'version': '3.8',
        'services': {},
        'networks': {
            'quantum-net': {
                'driver': 'bridge'
            }
        }
    }

    # Main quantum application service
    compose['services']['quantum-app'] = {
        'build': {
            'context': '.',
            'dockerfile': 'Dockerfile'
        },
        'image': f'{app_name}:dev',
        'container_name': f'{app_name}-dev',
        'volumes': [
            './src:/app/src:ro',
            './data:/app/data'
        ],
        'environment': [
            'PYTHONPATH=/app',
            'LOG_LEVEL=DEBUG'
        ],
        'env_file': ['.env.local'],
        'ports': [f'{app_port}:{app_port}'],
        'networks': ['quantum-net'],
        'healthcheck': {
            'test': ['CMD', 'python', '-c', 'import qiskit'],
            'interval': '30s',
            'timeout': '10s',
            'retries': 3
        }
    }

    # Jupyter notebook service
    if enable_jupyter:
        compose['services']['jupyter'] = {
            'build': {
                'context': '.',
                'dockerfile': 'Dockerfile.jupyter'
            },
            'image': f'{app_name}-jupyter:dev',
            'container_name': f'{app_name}-jupyter',
            'volumes': [
                './notebooks:/home/quantum/notebooks',
                './src:/home/quantum/src:ro'
            ],
            'environment': ['JUPYTER_TOKEN=quantum-dev'],
            'env_file': ['.env.local'],
            'ports': [f'{jupyter_port}:8888'],
            'networks': ['quantum-net']
        }

    # Redis cache service
    if enable_cache:
        compose['services']['cache'] = {
            'image': 'redis:7-alpine',
            'container_name': f'{app_name}-cache',
            'command': 'redis-server --maxmemory 256mb --maxmemory-policy allkeys-lru',
            'networks': ['quantum-net'],
            'healthcheck': {
                'test': ['CMD', 'redis-cli', 'ping'],
                'interval': '10s',
                'timeout': '5s',
                'retries': 3
            }
        }

    return yaml.dump(compose, default_flow_style=False, sort_keys=False)
